VALUES
  ('promotion-6e2f88c7-moex-00044', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '依公務人員考績法及實務見解，有關公務人員考績之敘述，下列何者正確？', '["行政機關對公務人員記大過處分，無懲處權時效之適用", "公務人員不服其服務機關所為考績丙等之評定，應以銓敘部為被告提起行政訴訟", "公務人員之年終考績丁等，效力為一次記兩大過免職", "考績應予免職人員，自確定之日起執行；未確定前，應先行停職"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00045', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '公務員甲之職務與下列各項人員或事業間有關，若甲與其成立借貸關係，何者不違反公務員服務法？', '["承包甲任職機關之工程廠商", "受有甲任職機關之上級機關補助者", "與甲任職機關間曾有行政爭訟者", "甲任職機關來往款項之銀行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00046', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '公務人員對於服務機關或人事主管機關所為之行政處分，認為違法或顯然不當，致損害其權利或 利益者，依法得提起何種救濟？', '["審議", "復審", "申訴", "聲明異議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00047', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '依行政程序法規定，有關法規命令與行政規則之敘述，下列何者錯誤？', '["法規命令應有法律之授權", "行政規則具有拘束訂定機關、其下級機關及屬官之效力", "法規命令直接對外發生法律效果，行政規則非直接對外發生法規範效力", "法規命令經發布後未依法函送立法院者無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00048', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '主管機關為推動各機關（構）、公營事業機構節能減碳，依職權訂定獎勵節能要點，各機關（構） 如經主管機關評比為節能措施實施成效良好者，將給予獎勵。關於此要點之法律性質，下列敘述 何者正確？', '["本要點為實現重要公共利益而訂定，適用範圍及於主管機關之外的機關或機構，性質屬法規命令", "本要點為主管機關辦理節能措施評比獎勵之依據，屬機關業務處理的一般性規定，故為指令", "即使相關法規未課予主管機關推動節能減碳措施之義務，其仍可訂定要點執行評比與獎勵", "因獎勵涉及動用國家財政預算，為落實民主原則，應依立法院通過法律明文授權始得辦理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00049', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '考生持國立大學畢業證書報名參加國家考試，該畢業證書對辦理考試機關之拘束力，係屬下列何者？', '["形式存續力", "構成要件效力", "執行力", "確認效力 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、70130 71130"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00050', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '依行政程序法規定，下列何者非屬應予廢止之情形？', '["主管機關核發建築執照後發現申請人於申請時所提出之土地使用同意書為偽造", "主管機關准予變更土地編定時，附記申請人應提出土地使用計畫書並配置必要公共設施，事後 申請人並未履行", "勞動部核發外籍家庭照護工聘用許可後，雇主死亡", "外國人經內政部移民署核發居留許可入境後，其有重大危害公共安全之情形"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00051', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '關於行政機關之管轄，下列敘述何者正確？', '["行政機關對事件管轄權之有無，應依職權調查；其認無管轄權者，應即移送司法機關，並通知 當事人", "行政機關得依法規將其權限之一部分，委任民間團體或個人辦理", "行政機關因業務上之需要，得依法規將其權限之一部分，委託不相隸屬之行政機關執行之", "數行政機關於管轄權有爭議時，應由司法機關指定管轄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00052', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '關於行政契約之敘述，下列何者正確？', '["行政契約與行政處分乃不同性質之行政作用，故行政機關有作成行政處分權限時，即不可再締 結行政契約", "國民住宅之買賣契約屬於取代行政處分之行政契約", "行政契約原則上是屬於要式行為", "行政契約依約定內容履行將侵害第三人之權利者，應經該第三人書面或口頭之同意，始生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00053', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '主管機關建議農民甲停種作物並輔導休耕，甲表示不同意，依行政程序法規定，該機關應如何為 適法之處理？', '["以甲為相對人作成行政處分，命其休耕", "對甲裁處罰鍰，並於甲休耕前，得連續處罰", "應派員親至當地強制執行休耕", "應停止繼續建議或輔導"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL)
